What does this program print?

```cpp
#include <iostream>
struct Score {
    int value{};
    bool operator==(const Score& rhs) const { return value == rhs.value; }
    bool operator!=(const Score& rhs) const { return !(*this == rhs); }
};
int main() {
    Score a{ 10 }, b{ 10 }, c{ 20 };
    std::cout << (a == b) << ' ' << (a != c) << '\n';
}
```

